  let accountIndex = 0;
  const getNextAccount = () => {
    const accountMeta = (instruction.accounts as TAccountMetas)[accountIndex]!;
    accountIndex += 1;
    return accountMeta;
  };
  const getNextOptionalAccount = () => {
    const accountMeta = getNextAccount();
    return accountMeta.address === FLOW_PROGRAM_ADDRESS
      ? undefined
      : accountMeta;
  };
  return {
    programAddress: instruction.programAddress,
    accounts: {
      signer: getNextAccount(),
      game: getNextAccount(),
      holderPlayer: getNextAccount(),
      nextPlayer: getNextAccount(),
      sessionToken: getNextOptionalAccount(),
      priceFeed: getNextAccount(),
    },
    data: getPassInstructionDataDecoder().decode(instruction.data),
  };
